function solve(nums: number[]): number {
    const maxNum = 1000000;
    const sieve = new Array(maxNum + 1).fill(true);
    sieve[0] = sieve[1] = false;
    for (let i = 2; i <= Math.sqrt(maxNum); i++) {
        if (sieve[i]) {
            for (let j = i * i; j <= maxNum; j += i) {
                sieve[j] = false;
            }
        }
    }

    const spf = new Array(maxNum + 1).fill(0);
    for (let i = 2; i <= maxNum; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * 2; j <= maxNum; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }

    const primeToIndices = new Map<number, number[]>();
    for (let j = 0; j < nums.length; j++) {
        const num = nums[j];
        if (num === 1) continue;
        const primes = new Set<number>();
        let n = num;
        while (n > 1) {
            const p = spf[n];
            primes.add(p);
            while (n % p === 0) {
                n /= p;
            }
        }
        for (const p of primes) {
            if (!primeToIndices.has(p)) {
                primeToIndices.set(p, []);
            }
            primeToIndices.get(p)!.push(j);
        }
    }

    const n = nums.length;
    if (n === 0) return 0;
    const visited = new Array(n).fill(false);
    const queue: [number, number][] = [[0, 0]];
    visited[0] = true;

    while (queue.length > 0) {
        const [current, steps] = queue.shift()!;
        if (current === n - 1) return steps;

        const nextPositions: number[] = [];
