        if (current < n - 1 && !visited[current + 1]) nextPositions.push(current + 1);

        if (sieve[nums[current]]) {
            const p = nums[current];
            const indices = primeToIndices.get(p) || [];
            for (const j of indices) {
                if (j !== current && !visited[j]) nextPositions.push(j);
            }
        }

        for (const pos of nextPositions) {
            visited[pos] = true;
            queue.push([pos, steps + 1]);
        }
    }

    return -1;
